const $ = (selector, root = document) => root.querySelector(selector);
const $$ = (selector, root = document) => Array.from(root.querySelectorAll(selector));
const state = {
  token: sessionStorage.getItem("roonia.portal.token"), view: "home", musicTab: "search",
  playbackTab: "zones", adminTab: "access", dashboard: null, zones: [], outputs: [],
  playlists: [], selectedPlaylist: null, search: null, keys: [], tools: [], presets: [],
  volumeLimits: [], browse: { hierarchy: "browse", session: "portal-visual-browse", trail: [] }
};

const esc = (value) => String(value ?? "").replace(/[&<>'"]/g, (char) => ({ "&":"&amp;","<":"&lt;",">":"&gt;","'":"&#39;",'"':"&quot;" }[char]));
const fmtDate = (value) => value ? new Intl.DateTimeFormat("es-ES", { dateStyle:"medium", timeStyle:"short" }).format(new Date(value)) : "Nunca";
const icon = (name) => `<span class="material-symbols-rounded">${name}</span>`;
const imageUrl = (key, size = 500) => key ? `/api/roon/images/${encodeURIComponent(key)}?width=${size}&height=${size}&scale=fill` : "";
const cover = (key, label = "", cls = "") => `<div class="cover ${cls}">${key ? `<img src="${imageUrl(key)}" alt="${esc(label)}" loading="lazy">` : `<div class="cover-fallback">${icon("music_note")}</div>`}</div>`;
const activeZone = () => state.zones.find((zone) => zone.state === "playing") || state.zones[0] || null;

async function api(path, options = {}) {
  if (path.endsWith("/zones/group") && options.body) {
    const payload = JSON.parse(options.body);
    if (Array.isArray(payload.zone_ids)) {
      payload.additional_zone_ids = payload.zone_ids.filter((id) => id !== payload.primary_zone_id);
      delete payload.zone_ids;
      options = { ...options, body: JSON.stringify(payload) };
    }
  }
  const headers = { ...(options.body ? { "Content-Type":"application/json" } : {}), ...(options.headers || {}) };
  if (state.token) headers.Authorization = `Bearer ${state.token}`;
  const response = await fetch(path, { ...options, headers });
  const type = response.headers.get("content-type") || "";
  const payload = type.includes("json") ? await response.json() : await response.text();
  if (!response.ok) {
    if (response.status === 401 && !path.includes("/auth/")) showAuth();
    throw new Error(payload?.error?.message || payload?.message || `Error ${response.status}`);
  }
  return payload;
}
function toast(message, type = "ok") {
  const node = document.createElement("div"); node.className = `toast ${type === "error" ? "error" : ""}`;
  node.innerHTML = `${icon(type === "error" ? "error" : "check_circle")}<span>${esc(message)}</span>`;
  $("#toast-region").append(node); setTimeout(() => node.remove(), 4200);
}
function busy(button, on) { if (!button) return; button.disabled = on; button.dataset.label ||= button.innerHTML; button.innerHTML = on ? `${icon("progress_activity")} Cargando…` : button.dataset.label; }
function empty(title, text, glyph = "music_off") { return `<div class="empty-state"><div><span class="material-symbols-rounded">${glyph}</span><h3>${esc(title)}</h3><p>${esc(text)}</p></div></div>`; }
function openModal(html) { $("#modal-content").innerHTML = html; $("#modal").showModal(); }
function closeModal() { $("#modal").close(); $("#modal-content").innerHTML = ""; }
function modalHead(overline, title) { return `<div class="modal-head"><div><span class="overline">${esc(overline)}</span><h2>${esc(title)}</h2></div><button class="icon-btn" data-close>${icon("close")}</button></div>`; }
function formDataObject(form) { const out = {}; new FormData(form).forEach((value, key) => { if (out[key] !== undefined) out[key] = [].concat(out[key], value); else out[key] = value; }); return out; }

function showAuth(message = "") { $("#app").hidden = true; $("#auth-screen").hidden = false; if (message) $("#login-error").textContent = message; }
function showApp() { $("#auth-screen").hidden = true; $("#app").hidden = false; }
async function bootstrapAuth() {
  const status = await fetch("/api/auth/status").then((r) => r.json());
  $("#setup-form").hidden = !status.setup_required; $("#login-form").hidden = status.setup_required;
  if (status.setup_required) { $("#auth-overline").textContent = "Primera configuración"; $("#auth-title").textContent = "Crea tu espacio"; $("#auth-description").textContent = "Configura el primer administrador de roonIA."; }
  if (!state.token) return showAuth();
  try { const session = await api("/api/session"); $("#version-badge").textContent = `v${session.version}`; showApp(); await navigate(location.hash.slice(1) || "home"); }
  catch { state.token = null; sessionStorage.removeItem("roonia.portal.token"); showAuth(); }
}

async function navigate(view) {
  if (!['home','music','playback','admin'].includes(view)) view = 'home'; state.view = view; location.hash = view;
  $$(".view").forEach((node) => node.classList.toggle("active", node.id === `view-${view}`));
  $$(".nav-link").forEach((node) => node.classList.toggle("active", node.dataset.view === view));
  if (view === "home") await loadHome();
  if (view === "music") await loadMusicTab(state.musicTab);
  if (view === "playback") await loadPlaybackTab(state.playbackTab);
  if (view === "admin") await loadAdminTab(state.adminTab);
  window.scrollTo({ top:0, behavior:"smooth" });
}
function setTab(group, tab) {
  $$(`#${group}-tabs button`).forEach((node) => node.classList.toggle("active", node.dataset.tab === tab));
  const prefix = group === "music" ? "music" : group === "playback" ? "playback" : "admin";
  $$(`#view-${group === "playback" ? "playback" : group === "music" ? "music" : "admin"} > .tab-page`).forEach((node) => node.classList.toggle("active", node.id === `${prefix}-${tab}`));
}

async function loadHome() {
  const [dashboard, zones] = await Promise.all([api("/api/dashboard"), api("/api/roon/zones")]); state.dashboard = dashboard; state.zones = zones;
  const online = dashboard.status.core_connected; $("#connection-dot").classList.toggle("online", online); $("#connection-label").textContent = online ? (dashboard.status.core_name || "Roon conectado") : "Roon desconectado";
  $("#version-badge").textContent = `v${dashboard.version || "—"}`;
  const featured = zones.find((zone) => zone.state === "playing") || zones.find((zone) => zone.now_playing) || null;
  const np = featured?.now_playing?.three_line || {};
  $("#home-hero").classList.remove("skeleton-block"); $("#home-hero").innerHTML = featured ? `<div class="featured-backdrop">${featured.now_playing?.image_key ? `<img src="${imageUrl(featured.now_playing.image_key,1200)}" alt="">` : ""}</div><div class="featured-cover">${cover(featured.now_playing?.image_key,np.line1)}</div><div class="featured-content"><span class="overline">Ahora suena · ${esc(featured.display_name)}</span><h1>${esc(np.line1 || "Música en Roon")}</h1><p class="featured-artist">${esc(np.line2 || "")}</p><p class="featured-album">${esc(np.line3 || "")}</p><div class="featured-controls" data-zone="${esc(featured.zone_id)}"><button class="icon-btn" data-zone-command="previous" title="Anterior">${icon("skip_previous")}</button><button class="play-main" data-zone-command="playpause" title="Pausa">${icon(featured.state === "playing" ? "pause" : "play_arrow")}</button><button class="icon-btn" data-zone-command="next" title="Siguiente">${icon("skip_next")}</button><button class="btn text" data-go="playback">Abrir zona ${icon("arrow_forward")}</button></div></div><div class="featured-meta"><span>${online ? esc(dashboard.status.core_name || "Roon Core") : "Core desconectado"}</span><span>${dashboard.counts.playlists} playlists · ${dashboard.counts.playlist_tracks} pistas</span></div>` : `<div class="featured-content empty-feature"><span class="overline">${online ? "Roon está preparado" : "Core sin conexión"}</span><h1>${greeting()}</h1><p>Busca un álbum, artista o canción para empezar a escuchar.</p><button class="btn primary" data-quick="music:search">${icon("search")}Buscar música</button></div>`;
  renderHomeNow(); renderQuickActions(); renderActivity($("#home-activity"), dashboard.recent_actions || []); renderMiniPlayer();
}
function greeting() { const hour = new Date().getHours(); return hour < 12 ? "Buenos días" : hour < 20 ? "Buenas tardes" : "Buenas noches"; }
function renderHomeNow() {
  $("#home-now-playing").innerHTML = state.zones.length ? state.zones.map((zone) => { const np = zone.now_playing?.three_line || {}; const playing = zone.state === "playing"; return `<article class="now-card" data-zone="${esc(zone.zone_id)}">${cover(zone.now_playing?.image_key, np.line1)}<div class="now-info"><div class="now-zone"><i class="${playing ? "online" : ""}"></i>${esc(zone.display_name)}</div><h3>${esc(np.line1 || "En silencio")}</h3><p>${esc(np.line2 || np.line3 || "Nada en reproducción")}</p></div><div class="now-controls"><button class="icon-btn" data-zone-command="playpause" title="${playing ? "Pausar" : "Reproducir"}">${icon(playing ? "pause" : "play_arrow")}</button><button class="icon-btn" data-queue title="Abrir cola">${icon("queue_music")}</button></div></article>`; }).join("") : empty("No hay zonas", "Roon todavía no ha publicado ninguna zona.", "speaker_group");
}
function renderQuickActions() { $("#quick-actions").innerHTML = [["search","Buscar música","Artistas, álbumes y pistas","music:search"],["queue_music","Playlists","Tus colecciones virtuales","music:playlists"],["speaker_group","Zonas","Control multiroom","playback:zones"],["key","Accesos","API keys y permisos","admin:access"]].map(([i,t,s,go]) => `<button class="quick-card" data-quick="${go}">${icon(i)}<span><strong>${t}</strong><small>${s}</small></span></button>`).join(""); }
function renderActivity(root, actions) { root.innerHTML = actions.length ? actions.map((item) => `<div class="activity-row"><span class="activity-icon">${icon(item.error_code ? "error" : item.source === "mcp" ? "smart_toy" : "bolt")}</span><span><strong>${esc(item.tool_or_endpoint || item.message || "Acción")}</strong><small>${esc(item.source || item.level || "portal")}${item.error_code ? ` · ${esc(item.error_code)}` : ""}</small></span><time>${fmtDate(item.timestamp)}</time></div>`).join("") : empty("Sin actividad reciente", "Las acciones aparecerán aquí.", "history"); }

async function loadMusicTab(tab) { state.musicTab = tab; setTab("music", tab); if (tab === "playlists") await loadPlaylists(); if (tab === "browse") await loadBrowse(true); }
async function searchMusic(query) {
  if (!query.trim()) return; $("#search-empty").hidden = true; $("#search-results").hidden = false; $("#search-results").innerHTML = empty("Buscando…", "Consultando tu biblioteca y servicios de streaming.", "progress_activity");
  state.search = await api(`/api/roon/media/search?q=${encodeURIComponent(query)}&types=track,album,artist,playlist&count=25`); renderSearchResults();
}
function renderSearchResults() {
  const results = state.search?.results || []; const groups = { artist:[], album:[], track:[], playlist:[] }; results.forEach((result) => (groups[result.media_type] || groups.track).push(result));
  if (!results.length) { $("#search-results").innerHTML = empty("No encontramos resultados", "Prueba con menos palabras, otro artista o una ortografía distinta.", "search_off"); return; }
  const cards = (items, type) => `<div class="media-grid">${items.map((item) => `<button class="media-card ${type === "artist" ? "artist" : ""}" data-media-id="${esc(item.result_id)}">${cover(item.image_key,item.title)}<h3>${esc(item.title)}</h3><p>${esc(item.artist || item.subtitle || item.album || sourceLabel(item))}</p><span class="card-play" data-play-media="${esc(item.result_id)}">${icon(type === "artist" ? "radio" : "play_arrow")}</span></button>`).join("")}</div>`;
  const tracks = (items) => `<div class="track-list">${items.map((item,index) => `<div class="track-row" data-media-id="${esc(item.result_id)}"><span class="track-index">${index + 1}</span>${cover(item.image_key,item.title)}<span class="track-title"><strong>${esc(item.title)}</strong><small>${esc(item.artist || item.subtitle || "Artista desconocido")}</small></span><span class="track-album">${esc(item.album || sourceLabel(item))}</span><span class="row-actions">${item.is_best_match ? `<span class="media-badge best">Mejor resultado</span>` : ""}<button class="icon-btn" data-play-media="${esc(item.result_id)}" title="Reproducir">${icon("play_arrow")}</button><button class="icon-btn" data-add-playlist="${esc(item.result_id)}" title="Añadir a playlist">${icon("playlist_add")}</button><button class="icon-btn" data-media-id-button="${esc(item.result_id)}" title="Más información">${icon("more_horiz")}</button></span></div>`).join("")}</div>`;
  const sections = [["artist","Artistas"],["album","Álbumes"],["track","Canciones"],["playlist","Playlists de Roon"]].filter(([key]) => groups[key].length).map(([key,title]) => `<section class="result-section"><div class="result-heading"><h2>${title}</h2><span class="status-tag">${groups[key].length} resultados</span></div>${key === "track" ? tracks(groups[key]) : cards(groups[key],key)}</section>`).join("");
  $("#search-results").innerHTML = `<div class="section-title compact"><div><span class="overline">Resultados para</span><h2>“${esc(state.search.query)}”</h2></div>${state.search.ambiguous ? `<span class="status-tag warn">Hay varias coincidencias cercanas</span>` : ""}</div>${sections}`;
}
function sourceLabel(item) { return item.source && item.source !== "unknown" ? item.source[0].toUpperCase() + item.source.slice(1) : item.media_type; }
async function openMedia(resultId) {
  const item = state.search?.results?.find((result) => result.result_id === resultId) || await api(`/api/roon/media/${encodeURIComponent(resultId)}`);
  let releases = []; if (item.media_type === "artist") { try { releases = (await api(`/api/roon/media/${encodeURIComponent(resultId)}/releases?count=50`)).releases || []; } catch {} }
  openModal(`${modalHead(item.media_type === "artist" ? "Artista" : item.media_type === "album" ? "Álbum" : "Música", item.title)}<div class="entity-hero">${cover(item.image_key,item.title)}<div class="entity-copy"><span class="overline">${esc(sourceLabel(item))}${item.quality?.label ? ` · ${esc(item.quality.label)}` : ""}</span><h2>${esc(item.title)}</h2><p>${esc(item.artist || item.subtitle || item.album || "")}</p><div class="entity-meta">${item.is_library === true ? `<span class="media-badge">En tu biblioteca</span>` : ""}${item.version_hint ? `<span class="media-badge">${esc(item.version_hint)}</span>` : ""}</div><div class="inline-actions" style="margin-top:20px"><button class="btn primary" data-play-media="${esc(item.result_id)}">${icon("play_arrow")}Reproducir</button>${item.media_type === "artist" ? `<button class="btn secondary" data-radio-media="${esc(item.result_id)}">${icon("radio")}Iniciar radio</button>` : ""}<button class="btn secondary" data-add-playlist="${esc(item.result_id)}">${icon("playlist_add")}Añadir</button></div></div></div>${releases.length ? `<div class="modal-section"><h3>Discografía</h3><div class="media-grid">${releases.slice(0,12).map((release) => `<button class="media-card" data-media-id="${esc(release.result_id)}">${cover(release.image_key,release.title)}<h3>${esc(release.title)}</h3><p>${esc(release.subtitle || "Álbum")}</p></button>`).join("")}</div></div>` : ""}`);
}
async function chooseZoneAndPlay(resultId, mode = "replace_queue", radio = false) {
  if (!state.zones.length) state.zones = await api("/api/roon/zones");
  if (!state.zones.length) return toast("No hay zonas Roon disponibles", "error");
  if (state.zones.length === 1) return playMedia(resultId, state.zones[0].zone_id, mode, radio);
  openModal(`${modalHead("Destino", radio ? "Iniciar radio en…" : "Reproducir en…")}<div class="stack-list">${state.zones.map((zone) => `<button class="stack-row" data-zone-play="${esc(zone.zone_id)}" data-result="${esc(resultId)}" data-mode="${mode}" data-radio="${radio}"><span class="stack-row-icon">${icon("speaker")}</span><span class="stack-row-copy"><strong>${esc(zone.display_name)}</strong><small>${zone.state === "playing" ? "Reproduciendo" : "Disponible"}</small></span>${icon("arrow_forward")}</button>`).join("")}</div>`);
}
async function playMedia(resultId, zoneId, mode, radio) { await api(`/api/roon/media/${encodeURIComponent(resultId)}/${radio ? "radio" : "play"}`, { method:"POST", body:JSON.stringify({ zone_id:zoneId, mode }) }); closeModal(); toast(mode === "append" ? "Añadido a la cola" : "Reproducción iniciada"); await loadHome(); }

async function loadPlaylists() { const payload = await api("/api/playlists?limit=100&include_tracks=true&track_limit=4"); state.playlists = payload.playlists || []; $("#playlist-grid").innerHTML = state.playlists.length ? state.playlists.map(playlistCard).join("") : empty("Aún no hay playlists", "Crea una colección y añade música desde cualquier búsqueda.", "playlist_add"); }
function playlistCard(item) { const derived = item.cover_image_key || item.tracks?.find((track) => track.image_key)?.image_key; return `<button class="playlist-card" data-playlist="${esc(item.playlist_id)}"><div class="playlist-cover">${derived ? `<img src="${imageUrl(derived,700)}" alt="${esc(item.name)}">` : `<div class="cover-fallback">${icon("queue_music")}</div>`}</div><div class="playlist-card-body"><h3>${esc(item.name)}</h3><p>${esc(item.description || "Una playlist de roonIA")}</p><div class="playlist-meta"><span>${item.tracks_count || 0} canciones</span>${icon("arrow_forward")}</div></div></button>`; }
async function openPlaylist(id) { const playlist = await api(`/api/playlists/${encodeURIComponent(id)}?include_tracks=true&limit=500`); state.selectedPlaylist = playlist; openModal(`${modalHead("Playlist", playlist.name)}<div class="entity-hero">${cover(playlist.cover_image_key || playlist.tracks?.find((track) => track.image_key)?.image_key,playlist.name)}<div class="entity-copy"><span class="overline">${playlist.tracks_count} canciones</span><h2>${esc(playlist.name)}</h2><p>${esc(playlist.description || "Sin descripción")}</p><div class="inline-actions"><button class="btn primary" data-play-playlist="play_now">${icon("play_arrow")}Reproducir</button><button class="btn secondary" data-edit-playlist>${icon("edit")}Editar</button><button class="btn danger" data-delete-playlist>${icon("delete")}Eliminar</button></div></div></div><div class="modal-section"><div class="panel-head"><h3>Canciones</h3><button class="btn secondary small" data-add-track>${icon("add")}Añadir canción</button></div>${playlist.tracks?.length ? `<div class="track-list">${playlist.tracks.map((track,index) => `<div class="track-row" data-track="${esc(track.track_id)}"><span class="track-index">${index+1}</span>${cover(track.image_key,track.title)}<span class="track-title"><strong>${esc(track.title || track.query)}</strong><small>${esc(track.artist || "Sin artista")}</small></span><span class="track-album">${esc(track.album || track.resolution?.status || "")}</span><span class="row-actions"><button class="icon-btn" data-use-cover title="Usar como carátula">${icon("image")}</button><button class="icon-btn" data-remove-track title="Quitar">${icon("remove_circle")}</button></span></div>`).join("")}</div>` : empty("Playlist vacía", "Añade música desde la búsqueda o escribe una consulta.", "playlist_add")}</div>`); }
function playlistForm(playlist = null) { openModal(`${modalHead(playlist ? "Editar playlist" : "Nueva colección", playlist ? "Personaliza tu playlist" : "Crea una playlist")}<form id="playlist-form" class="modal-grid"><label class="full">Nombre<input name="name" required maxlength="100" value="${esc(playlist?.name || "")}"></label><label class="full">Descripción<textarea name="description" maxlength="300">${esc(playlist?.description || "")}</textarea></label><input type="hidden" name="playlist_id" value="${esc(playlist?.playlist_id || "")}"><div class="modal-actions full"><button type="button" class="btn secondary" data-close>Cancelar</button><button class="btn primary" type="submit">${playlist ? "Guardar cambios" : "Crear playlist"}</button></div></form>`); }
async function choosePlaylist(resultId) { if (!state.playlists.length) await loadPlaylists(); openModal(`${modalHead("Acción contextual", "Añadir a una playlist")}<div class="stack-list">${state.playlists.map((playlist) => `<button class="stack-row" data-target-playlist="${esc(playlist.playlist_id)}" data-result="${esc(resultId)}"><span class="stack-row-icon">${icon("queue_music")}</span><span class="stack-row-copy"><strong>${esc(playlist.name)}</strong><small>${playlist.tracks_count} canciones</small></span>${icon("add")}</button>`).join("")}</div><button class="btn secondary full" data-create-with-result="${esc(resultId)}">${icon("playlist_add")}Crear una nueva</button>`); }

async function loadBrowse(reset = false, itemKey = null, pop = 0) { if (reset) state.browse.trail = []; const params = new URLSearchParams({ hierarchy:state.browse.hierarchy, count:"100", session_key:state.browse.session }); if (itemKey) params.set("item_key", itemKey); if (pop) params.set("pop_levels",String(pop)); if (!itemKey && !pop) params.set("pop_all","true"); const result = await api(`/api/roon/library?${params}`); if (itemKey) state.browse.trail.push({ title:result.list?.title || "Nivel", itemKey }); if (pop) state.browse.trail.splice(-pop); renderBrowse(result); }
function renderBrowse(result) { $("#browse-breadcrumbs").innerHTML = `<span>Biblioteca</span>${state.browse.trail.map((item) => `${icon("chevron_right")}<strong>${esc(item.title)}</strong>`).join("")}`; $("#browse-heading").innerHTML = `<div><span class="overline">Explorar</span><h2>${esc(result.list?.title || state.browse.hierarchy)}</h2></div><span class="status-tag">${result.list?.count ?? result.items?.length ?? 0} elementos</span>`; $("#browse-grid").innerHTML = result.items?.length ? result.items.map((item) => `<button class="browse-row-card" data-browse-key="${esc(item.item_key || "")}" data-browse-hint="${esc(item.hint || "")}">${cover(item.image_key,item.title)}<span><strong>${esc(item.title)}</strong><small>${esc(item.subtitle || item.hint || "")}</small></span></button>`).join("") : empty("No hay elementos", "Roon no devolvió contenido para esta vista.", "folder_off"); }

async function loadPlaybackTab(tab) { state.playbackTab = tab; setTab("playback", tab); if (tab === "zones") await loadZones(); else { await loadPresets(); await loadOutputVolumes(); } }
async function loadZones() { const [zones, outputs] = await Promise.all([api("/api/roon/zones"),api("/api/roon/outputs")]); state.zones = zones; state.outputs = outputs; $("#zones-grid").innerHTML = zones.length ? zones.map(zoneCard).join("") : empty("No hay zonas disponibles", "Comprueba la conexión con Roon Core.", "speaker_group"); renderMiniPlayer(); }
function zoneVolume(zone) { return zone.outputs?.find((output) => output.volume)?.volume || null; }
function zoneCard(zone) { const np = zone.now_playing?.three_line || {}; const volume = zoneVolume(zone); const playing = zone.state === "playing"; return `<article class="zone-card" data-zone="${esc(zone.zone_id)}"><div class="zone-artwork">${zone.now_playing?.image_key ? `<img src="${imageUrl(zone.now_playing.image_key,800)}" alt="">` : ""}<span class="zone-status status-tag ${playing ? "good" : ""}">${playing ? "Reproduciendo" : esc(zone.state || "Disponible")}</span><div class="zone-card-head"><span class="overline">${esc(zone.display_name)}</span><h3>${esc(np.line1 || "Nada en reproducción")}</h3><p>${esc(np.line2 || np.line3 || "")}</p></div></div><div class="zone-body"><div class="zone-transport"><button class="icon-btn" data-zone-command="previous">${icon("skip_previous")}</button><button class="play-main" data-zone-command="playpause">${icon(playing ? "pause" : "play_arrow")}</button><button class="icon-btn" data-zone-command="next">${icon("skip_next")}</button></div>${volume ? `<div class="volume-control"><span class="material-symbols-rounded">volume_down</span><input type="range" min="${volume.min ?? 0}" max="${volume.max ?? 100}" step="${volume.step ?? 1}" value="${volume.value}" data-volume><output>${volume.value}</output></div>` : ""}<div class="zone-foot"><button class="btn secondary small" data-queue>${icon("queue_music")}Cola</button><button class="btn secondary small" data-transfer>${icon("move_up")}Transferir</button><button class="btn secondary small" data-ungroup>${icon("speaker_group")}Separar</button></div></div></article>`; }
async function zoneCommand(zoneId, command) { await api(`/api/roon/zones/${encodeURIComponent(zoneId)}/control`, { method:"POST",body:JSON.stringify({ command }) }); toast("Control enviado a Roon"); await loadZones(); }
async function openQueue(zoneId) { const queue = await api(`/api/roon/queue/${encodeURIComponent(zoneId)}`); openModal(`${modalHead("Cola de reproducción", state.zones.find((z) => z.zone_id === zoneId)?.display_name || "Zona")}<div class="track-list queue-list">${queue.items?.length ? queue.items.map((item,index) => `<div class="track-row"><span class="track-index">${index+1}</span>${cover(item.image_key,item.title)}<span class="track-title"><strong>${esc(item.title || "Pista")}</strong><small>${esc(item.subtitle || item.artist || "")}</small></span><span class="track-album">${item.is_current ? "Sonando ahora" : ""}</span><span></span></div>`).join("") : empty("La cola está vacía", "Añade música desde la búsqueda.", "queue_music")}</div>`); }
function openGrouping() { if (state.zones.length < 2) return toast("Necesitas al menos dos zonas", "error"); openModal(`${modalHead("Audio sincronizado", "Agrupar zonas")}<form id="group-form" class="modal-grid"><label class="full">Zona principal<select name="primary">${state.zones.map((z) => `<option value="${esc(z.zone_id)}">${esc(z.display_name)}</option>`).join("")}</select></label><div class="full permission-list">${state.zones.map((z) => `<label class="permission-item"><input type="checkbox" name="members" value="${esc(z.zone_id)}">${esc(z.display_name)}</label>`).join("")}</div><div class="modal-actions full"><button type="button" class="btn secondary" data-close>Cancelar</button><button class="btn primary" type="submit">Crear grupo</button></div></form>`); }
function openTransfer(sourceZoneId) { const targets = state.zones.filter((zone) => zone.zone_id !== sourceZoneId); if (!targets.length) return toast("No hay otra zona disponible", "error"); openModal(`${modalHead("Mover reproducción", "Transferir a otra zona")}<div class="stack-list">${targets.map((zone) => `<button class="stack-row" data-transfer-target="${esc(zone.zone_id)}" data-transfer-source="${esc(sourceZoneId)}"><span class="stack-row-icon">${icon("move_up")}</span><span class="stack-row-copy"><strong>${esc(zone.display_name)}</strong><small>La cola y la reproducción se moverán aquí</small></span>${icon("arrow_forward")}</button>`).join("")}</div>`); }
async function loadPresets() { const [presets, limits, outputs, zones] = await Promise.all([api("/api/zone-presets"),api("/api/volume-limits"),api("/api/roon/outputs"),api("/api/roon/zones")]); state.presets=presets;state.volumeLimits=limits;state.outputs=outputs;state.zones=zones; $("#preset-list").innerHTML = presets.length ? presets.map((preset) => `<div class="stack-row" data-preset="${esc(preset.preset_id)}"><span class="stack-row-icon">${icon("scene")}</span><span class="stack-row-copy"><strong>${esc(preset.name)}</strong><small>${esc(preset.description || `${preset.grouping?.members?.length || 0} miembros · ${preset.volumes?.length || 0} volúmenes`)}</small></span><span class="stack-row-actions"><button class="icon-btn" data-apply-preset title="Aplicar">${icon("play_arrow")}</button><button class="icon-btn" data-delete-preset title="Eliminar">${icon("delete")}</button></span></div>`).join("") : empty("Sin presets", "Guarda una escena multiroom para recuperarla en un toque.", "scene"); $("#output-volume-list").innerHTML = `<button class="btn secondary full" data-new-limit>${icon("add")}Nuevo límite seguro</button>${limits.map((limit) => `<div class="stack-row" data-limit="${esc(limit.limit_id)}"><span class="stack-row-icon">${icon("health_and_safety")}</span><span class="stack-row-copy"><strong>${esc(limit.name)}</strong><small>${esc(limit.target_ref.type)} · máximo ${limit.safe_max}${limit.schedule ? " · con horario" : ""}</small></span><span class="stack-row-actions"><button class="icon-btn" data-edit-limit>${icon("edit")}</button><button class="icon-btn" data-delete-limit>${icon("delete")}</button></span></div>`).join("")}`; }
function presetForm() { const options = [...state.outputs.map((o)=>[`output_id:${o.output_id}`,`Salida · ${o.display_name}`]),...state.zones.map((z)=>[`zone_id:${z.zone_id}`,`Zona · ${z.display_name}`])]; openModal(`${modalHead("Nueva escena", "Crear preset de zonas")}<form id="preset-form" class="modal-grid"><label class="full">Nombre<input name="name" required></label><label class="full">Descripción<textarea name="description"></textarea></label><label class="full">Principal<select name="primary">${options.map(([v,l])=>`<option value="${esc(v)}">${esc(l)}</option>`).join("")}</select></label><div class="full permission-list">${options.map(([v,l])=>`<label class="permission-item"><input type="checkbox" name="members" value="${esc(v)}">${esc(l)}</label>`).join("")}</div><div class="modal-actions full"><button type="button" class="btn secondary" data-close>Cancelar</button><button class="btn primary" type="submit">Guardar preset</button></div></form>`); }
function limitForm(limit=null) { const options=[['global:global','Global'],...state.outputs.map((o)=>[`output_id:${o.output_id}`,o.display_name]),...state.zones.map((z)=>[`zone_id:${z.zone_id}`,z.display_name])]; openModal(`${modalHead("Escucha segura",limit?"Editar límite":"Nuevo límite de volumen")}<form id="limit-form" class="modal-grid"><input type="hidden" name="limit_id" value="${esc(limit?.limit_id||"")}"><label class="full">Nombre<input name="name" required value="${esc(limit?.name||"Límite seguro")}"></label><label>Objetivo<select name="target">${options.map(([v,l])=>`<option value="${esc(v)}" ${limit && `${limit.target_ref.type}:${limit.target_ref.value}`===v?'selected':''}>${esc(l)}</option>`).join("")}</select></label><label>Volumen máximo<input name="safe_max" type="number" required min="1" value="${esc(limit?.safe_max||"")}"></label><div class="modal-actions full"><button type="button" class="btn secondary" data-close>Cancelar</button><button class="btn primary" type="submit">Guardar</button></div></form>`); }
async function loadOutputVolumes() { state.outputVolumes = await api("/api/admin/output-volumes"); const root = $("#output-volume-list"); const configured = state.outputVolumes.map((item) => { const settings = item.settings || {}; const current = item.current_volume?.value; return `<div class="stack-row" data-output-settings="${esc(item.output_id)}"><span class="stack-row-icon">${icon("volume_up")}</span><span class="stack-row-copy"><strong>${esc(item.display_name)}</strong><small>Actual ${current ?? "—"} · preferido ${settings.preferred_value ?? "sin definir"}</small><span class="inline-actions wrap" style="margin-top:9px"><input data-output-min type="number" step="0.5" placeholder="Mín." value="${settings.minimum_value ?? ""}" style="width:76px"><input data-output-max type="number" step="0.5" placeholder="Máx." value="${settings.maximum_value ?? ""}" style="width:76px"><input data-output-preferred type="number" step="0.5" placeholder="Preferido" value="${settings.preferred_value ?? ""}" style="width:96px"></span></span><span class="stack-row-actions"><button class="icon-btn" data-save-output title="Guardar valores">${icon("save")}</button><button class="icon-btn" data-apply-output title="Aplicar volumen preferido">${icon("play_arrow")}</button></span></div>`; }).join(""); const limits = state.volumeLimits.map((limit) => `<div class="stack-row" data-limit="${esc(limit.limit_id)}"><span class="stack-row-icon">${icon("health_and_safety")}</span><span class="stack-row-copy"><strong>${esc(limit.name)}</strong><small>${esc(limit.target_ref.type)} · máximo ${limit.safe_max}${limit.schedule ? " · con horario" : ""}</small></span><span class="stack-row-actions"><button class="icon-btn" data-edit-limit>${icon("edit")}</button><button class="icon-btn" data-delete-limit>${icon("delete")}</button></span></div>`).join(""); root.innerHTML = `<div class="panel-head" style="margin:4px 0 8px"><div><span class="overline">Valores preferidos</span></div></div>${configured || empty("Sin salidas", "Roon todavía no ha publicado salidas.", "volume_off")}<div class="panel-head" style="margin:24px 0 8px"><div><span class="overline">Límites de seguridad</span></div><button class="btn secondary small" data-new-limit>${icon("add")}Nuevo</button></div>${limits || empty("Sin límites", "No hay límites de seguridad configurados.", "health_and_safety")}`; }

document.addEventListener('click',(e)=>{const row=e.target.closest('[data-output-settings]');if(!row)return;if(e.target.closest('[data-save-output]'))api(`/api/admin/output-volumes/${encodeURIComponent(row.dataset.outputSettings)}`,{method:'PUT',body:JSON.stringify({minimum_value:row.querySelector('[data-output-min]').value,maximum_value:row.querySelector('[data-output-max]').value,preferred_value:row.querySelector('[data-output-preferred]').value})}).then(()=>{toast('Valores de volumen guardados');loadOutputVolumes()}).catch(err=>toast(err.message,'error'));if(e.target.closest('[data-apply-output]'))api(`/api/admin/output-volumes/${encodeURIComponent(row.dataset.outputSettings)}/apply`,{method:'POST',body:'{}'}).then(()=>{toast('Volumen preferido aplicado');loadOutputVolumes()}).catch(err=>toast(err.message,'error'));});

async function loadAdminTab(tab) { state.adminTab=tab; setTab("admin",tab); if(tab==='access')await loadKeys();if(tab==='tools')await loadTools();if(tab==='operation')await loadOperation();if(tab==='system')await loadSystem(); }
async function loadKeys(){state.keys=await api('/api/admin/api-keys');$("#keys-list").innerHTML=state.keys.length?state.keys.map((key)=>`<div class="key-row ${key.revoked_at?'revoked':''}" data-key="${esc(key.key_id)}"><span class="key-icon">${icon(key.revoked_at?'key_off':'key')}</span><span class="key-copy"><strong>${esc(key.name)}</strong><small>${esc(key.key_prefix)}</small></span><span class="role-badge">${esc(key.role)}</span><span class="key-detail">${key.tool_permissions===null?'Todas las tools':`${key.tool_permissions.length} tools permitidas`}<br>Uso: ${fmtDate(key.last_used_at)}</span><span class="key-actions"><button class="icon-btn" data-edit-key title="Editar permisos">${icon("tune")}</button>${key.revoked_at?`<button class="icon-btn" data-reactivate-key title="Reactivar">${icon("restart_alt")}</button>`:`<button class="icon-btn" data-revoke-key title="Revocar">${icon("delete")}</button>`}</span></div>`).join(""):empty('No hay API keys','Crea una para conectar clientes externos.','key');}
async function keyForm(key=null){if(!state.tools.length)await loadTools(false);const permissions=key?.tool_permissions;openModal(`${modalHead(key?'Permisos avanzados':'Nueva credencial',key?'Editar API key':'Crear API key')}<form id="key-form" class="modal-grid"><input type="hidden" name="key_id" value="${esc(key?.key_id||'')}"><label class="full">Nombre<input name="name" required maxlength="80" value="${esc(key?.name||'')}"></label><label class="full">Rol<select name="role"><option value="read" ${key?.role==='read'?'selected':''}>Lectura</option><option value="control" ${!key||key.role==='control'?'selected':''}>Control</option><option value="admin" ${key?.role==='admin'?'selected':''}>Administrador</option></select></label><label class="toggle-row full"><span><strong>Acceso a todas las tools</strong><small style="display:block;color:var(--ink-3);margin-top:4px">Desactívalo para crear una lista permitida</small></span><input class="switch" type="checkbox" name="all_tools" ${permissions===null||!key?'checked':''}></label><div class="full permission-list" id="key-permissions">${state.tools.map((tool)=>`<label class="permission-item"><input type="checkbox" name="tools" value="${esc(tool.name)}" ${permissions===null||permissions?.includes(tool.name)?'checked':''}>${esc(tool.name)}</label>`).join('')}</div><div class="modal-actions full"><button type="button" class="btn secondary" data-close>Cancelar</button><button class="btn primary" type="submit">${key?'Guardar permisos':'Crear key'}</button></div></form>`);togglePermissionList();}
function togglePermissionList(){const form=$("#key-form");if(!form)return;const all=form.elements.all_tools.checked;$("#key-permissions").style.opacity=all?'.42':'1';$$('input[name=tools]',form).forEach((input)=>input.disabled=all);}
async function loadTools(render=true){const payload=await api('/api/admin/tools');state.tools=payload.tools||[];if(!render)return;renderTools();}
function renderTools(){const q=$("#tool-filter").value.toLowerCase();const cls=$("#tool-class-filter").value;const tools=state.tools.filter((tool)=>`${tool.name} ${tool.title} ${tool.description}`.toLowerCase().includes(q)).filter((tool)=>cls==='all'||(cls==='read'&&tool.classification.read_only)||(cls==='write'&&!tool.classification.read_only)||(cls==='disabled'&&!tool.enabled));$("#tool-summary").innerHTML=`<strong>${state.tools.filter(t=>t.enabled).length}</strong> activas de ${state.tools.length}`;$("#tools-list").innerHTML=tools.map((tool)=>`<div class="tool-row ${tool.enabled?'':'disabled'}" data-tool="${esc(tool.name)}"><span class="tool-name"><strong>${esc(tool.name)}</strong><small>${esc(tool.title)}</small></span><span class="tool-description">${esc(tool.description)}</span><span class="tool-type">${icon(tool.classification.read_only?'visibility':'bolt')}${tool.classification.read_only?'Lectura':'Acción'}</span><input class="switch" type="checkbox" data-tool-toggle ${tool.enabled?'checked':''} aria-label="Habilitar ${esc(tool.name)}"></div>`).join('')||empty('Ninguna tool coincide','Cambia el filtro de búsqueda.','filter_alt_off');}
async function loadOperation(){const [diag,actions,logs]=await Promise.all([api('/api/diagnostics/bundle'),api('/api/observability/actions?limit=50'),api('/api/logs/recent?limit=50')]);const ready=diag.http?.ready;$("#admin-health-badge").classList.toggle('online',ready);$("#admin-health-badge").innerHTML=`<i></i>${ready?'Sistema preparado':'Atención requerida'}`;$("#operation-health").innerHTML=[[diag.roon?.core_connected?'Sí':'No','Core conectado'],[diag.roon?.zones_count||0,'Zonas'],[diag.mcp?.tools_count||0,'Tools MCP'],[diag.recent_errors?.length||0,'Errores recientes']].map(([v,l])=>`<div class="health-metric"><strong>${v}</strong><span>${l}</span></div>`).join('');renderActivity($("#action-log-list"),actions.actions||[]);renderActivity($("#technical-log-list"),logs.events||logs.logs||[]);$("#diagnostics-preview").textContent=JSON.stringify(diag,null,2);}
async function loadSystem(){const [settings,system]=await Promise.all([api('/api/admin/settings'),api('/api/admin/system')]);$("#system-api-port").value=system.runtime_config?.api_port||settings.api_port;$("#system-portal-port").value=system.runtime_config?.portal_port||settings.portal_port;$("#system-allow-beta").checked=settings.allow_beta_updates;$("#service-addresses").innerHTML=(system.addresses||[]).map((a)=>`<div class="address-row"><span>${esc(a.interface||a.name||'Dirección')}</span><code>${esc(a.portal_url||a.address||a)}</code></div>`).join('')||`<div class="address-row"><span>URL pública</span><code>${esc(settings.public_base_url)}</code></div>`;$("#settings-grid").innerHTML=Object.entries(settings).filter(([k])=>!k.includes('token')).map(([k,v])=>`<div class="setting-row"><span>${esc(k.replaceAll('_',' '))}</span><strong>${typeof v==='boolean'?(v?'Sí':'No'):esc(v)}</strong></div>`).join('');}
function renderMiniPlayer(){const zone=activeZone();const footer=$("#mini-player");if(!zone||zone.state!=='playing'){footer.hidden=true;return;}const np=zone.now_playing?.three_line||{};footer.hidden=false;footer.innerHTML=`<div class="mini-track">${cover(zone.now_playing?.image_key,np.line1)}<span><strong>${esc(np.line1||'Reproduciendo')}</strong><small>${esc(np.line2||'')}</small></span></div><div class="mini-controls"><button class="icon-btn skip" data-mini-command="previous">${icon('skip_previous')}</button><button class="main" data-mini-command="playpause">${icon('pause')}</button><button class="icon-btn skip" data-mini-command="next">${icon('skip_next')}</button></div><div class="mini-zone">${icon('speaker')} ${esc(zone.display_name)}</div>`;}

// Authentication
$("#setup-form").addEventListener("submit",async(e)=>{e.preventDefault();const b=$("#setup-form button");try{if($("#setup-password").value!==$("#setup-password-confirm").value)throw new Error('Las contraseñas no coinciden');busy(b,true);const payload=await fetch('/api/auth/setup',{method:'POST',headers:{Authorization:`Bearer ${$("#setup-bootstrap").value}`,'Content-Type':'application/json'},body:JSON.stringify({username:$("#setup-username").value,password:$("#setup-password").value})}).then(async r=>{const p=await r.json();if(!r.ok)throw new Error(p.error?.message);return p});state.token=payload.token;sessionStorage.setItem('roonia.portal.token',state.token);showApp();await navigate('home');}catch(err){$("#setup-error").textContent=err.message}finally{busy(b,false)}});
$("#login-form").addEventListener("submit",async(e)=>{e.preventDefault();const b=$("#login-form button");try{busy(b,true);const payload=await fetch('/api/auth/login',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({username:$("#login-username").value,password:$("#login-password").value})}).then(async r=>{const p=await r.json();if(!r.ok)throw new Error(p.error?.message);return p});state.token=payload.token;sessionStorage.setItem('roonia.portal.token',state.token);showApp();await navigate('home');}catch(err){$("#login-error").textContent=err.message}finally{busy(b,false)}});
$("#logout").addEventListener('click',async()=>{try{await api('/api/auth/logout',{method:'POST'})}catch{}state.token=null;sessionStorage.removeItem('roonia.portal.token');showAuth();});

// Navigation and tabs
$("#main-nav").addEventListener('click',(e)=>{const b=e.target.closest('[data-view]');if(b)navigate(b.dataset.view).catch(err=>toast(err.message,'error'))});
document.addEventListener('click',(e)=>{const go=e.target.closest('[data-go]');if(go)navigate(go.dataset.go).catch(err=>toast(err.message,'error'));const quick=e.target.closest('[data-quick]');if(quick){const [view,tab]=quick.dataset.quick.split(':');if(view==='music')state.musicTab=tab;if(view==='playback')state.playbackTab=tab;if(view==='admin')state.adminTab=tab;navigate(view).catch(err=>toast(err.message,'error'));}const admin=e.target.closest('[data-admin-tab]');if(admin){state.adminTab=admin.dataset.adminTab;navigate('admin').catch(err=>toast(err.message,'error'));}});
$("#music-tabs").addEventListener('click',(e)=>{const b=e.target.closest('[data-tab]');if(b)loadMusicTab(b.dataset.tab).catch(err=>toast(err.message,'error'))});$("#playback-tabs").addEventListener('click',(e)=>{const b=e.target.closest('[data-tab]');if(b)loadPlaybackTab(b.dataset.tab).catch(err=>toast(err.message,'error'))});$("#admin-tabs").addEventListener('click',(e)=>{const b=e.target.closest('[data-tab]');if(b)loadAdminTab(b.dataset.tab).catch(err=>toast(err.message,'error'))});
$("#refresh").addEventListener('click',()=>navigate(state.view).catch(err=>toast(err.message,'error')));window.addEventListener('hashchange',()=>{const view=location.hash.slice(1);if(view&&view!==state.view)navigate(view).catch(err=>toast(err.message,'error'))});
document.addEventListener('keydown',(e)=>{if((e.ctrlKey||e.metaKey)&&e.key.toLowerCase()==='k'){e.preventDefault();$("#global-search-input").focus();}});
$("#global-search").addEventListener('submit',async(e)=>{e.preventDefault();const q=$("#global-search-input").value;state.musicTab='search';await navigate('music');$("#music-query").value=q;await searchMusic(q).catch(err=>toast(err.message,'error'));});$("#music-search-form").addEventListener('submit',(e)=>{e.preventDefault();searchMusic($("#music-query").value).catch(err=>toast(err.message,'error'))});

// Delegated media actions
$("#search-results").addEventListener('click',(e)=>{const play=e.target.closest('[data-play-media]');const add=e.target.closest('[data-add-playlist]');const more=e.target.closest('[data-media-id-button]');if(play){e.stopPropagation();chooseZoneAndPlay(play.dataset.playMedia).catch(err=>toast(err.message,'error'));return}if(add){e.stopPropagation();choosePlaylist(add.dataset.addPlaylist).catch(err=>toast(err.message,'error'));return}if(more){openMedia(more.dataset.mediaIdButton).catch(err=>toast(err.message,'error'));return}const card=e.target.closest('[data-media-id]');if(card)openMedia(card.dataset.mediaId).catch(err=>toast(err.message,'error'));});
$("#new-playlist").addEventListener('click',()=>playlistForm());$("#playlist-grid").addEventListener('click',(e)=>{const card=e.target.closest('[data-playlist]');if(card)openPlaylist(card.dataset.playlist).catch(err=>toast(err.message,'error'))});
$("#browse-hierarchy").addEventListener('change',(e)=>{state.browse.hierarchy=e.target.value;loadBrowse(true).catch(err=>toast(err.message,'error'))});$("#browse-home").addEventListener('click',()=>loadBrowse(true).catch(err=>toast(err.message,'error')));$("#browse-back").addEventListener('click',()=>loadBrowse(false,null,1).catch(err=>toast(err.message,'error')));$("#browse-grid").addEventListener('click',(e)=>{const item=e.target.closest('[data-browse-key]');if(!item)return;if(item.dataset.browseHint==='action')api('/api/roon/browse/action',{method:'POST',body:JSON.stringify({hierarchy:state.browse.hierarchy,item_key:item.dataset.browseKey,session_key:state.browse.session,zone_id:activeZone()?.zone_id})}).then(()=>toast('Acción ejecutada')).catch(err=>toast(err.message,'error'));else loadBrowse(false,item.dataset.browseKey).catch(err=>toast(err.message,'error'));});

// Playback
$("#home-now-playing").addEventListener('click',(e)=>{const queue=e.target.closest('[data-queue]');const zone=e.target.closest('[data-zone]');if(queue&&zone)openQueue(zone.dataset.zone).catch(err=>toast(err.message,'error'));});
document.addEventListener('click',(e)=>{const command=e.target.closest('[data-zone-command]');if(command){const zone=command.closest('[data-zone]');zoneCommand(zone.dataset.zone,command.dataset.zoneCommand).catch(err=>toast(err.message,'error'));}});$("#zones-grid").addEventListener('change',(e)=>{if(!e.target.matches('[data-volume]'))return;const card=e.target.closest('[data-zone]');const zone=state.zones.find(z=>z.zone_id===card.dataset.zone);const output=zone.outputs?.find(o=>o.volume);api(`/api/roon/outputs/${encodeURIComponent(output.output_id)}/volume`,{method:'POST',body:JSON.stringify({mode:'absolute',value:Number(e.target.value)})}).then(()=>{e.target.nextElementSibling.value=e.target.value;toast('Volumen actualizado')}).catch(err=>toast(err.message,'error'));});$("#zones-grid").addEventListener('click',(e)=>{const card=e.target.closest('[data-zone]');if(!card)return;if(e.target.closest('[data-queue]'))openQueue(card.dataset.zone).catch(err=>toast(err.message,'error'));if(e.target.closest('[data-ungroup]'))api(`/api/roon/zones/${encodeURIComponent(card.dataset.zone)}/ungroup`,{method:'POST',body:'{}'}).then(loadZones).catch(err=>toast(err.message,'error'));if(e.target.closest('[data-transfer]'))openTransfer(card.dataset.zone)});$("#pause-all").addEventListener('click',()=>api('/api/roon/pause-all',{method:'POST',body:'{}'}).then(loadZones).catch(err=>toast(err.message,'error')));$("#mute-all").addEventListener('click',()=>api('/api/roon/mute-all',{method:'POST',body:JSON.stringify({action:'mute'})}).then(loadZones).catch(err=>toast(err.message,'error')));$("#open-group").addEventListener('click',openGrouping);
$("#new-preset").addEventListener('click',presetForm);$("#preset-list").addEventListener('click',(e)=>{const row=e.target.closest('[data-preset]');if(!row)return;if(e.target.closest('[data-apply-preset]'))api(`/api/zone-presets/${encodeURIComponent(row.dataset.preset)}/apply`,{method:'POST',body:JSON.stringify({confirm:true})}).then(()=>toast('Preset aplicado')).catch(err=>toast(err.message,'error'));if(e.target.closest('[data-delete-preset]')&&confirm('¿Eliminar este preset?'))api(`/api/zone-presets/${encodeURIComponent(row.dataset.preset)}`,{method:'DELETE'}).then(loadPresets).catch(err=>toast(err.message,'error'));});$("#output-volume-list").addEventListener('click',(e)=>{if(e.target.closest('[data-new-limit]'))limitForm();const row=e.target.closest('[data-limit]');if(!row)return;const limit=state.volumeLimits.find(l=>l.limit_id===row.dataset.limit);if(e.target.closest('[data-edit-limit]'))limitForm(limit);if(e.target.closest('[data-delete-limit]')&&confirm('¿Eliminar este límite?'))api(`/api/volume-limits/${encodeURIComponent(row.dataset.limit)}`,{method:'DELETE'}).then(loadPresets).catch(err=>toast(err.message,'error'));});

// Admin
$("#new-key").addEventListener('click',()=>keyForm().catch(err=>toast(err.message,'error')));$("#keys-list").addEventListener('click',(e)=>{const row=e.target.closest('[data-key]');if(!row)return;const key=state.keys.find(k=>k.key_id===row.dataset.key);if(e.target.closest('[data-edit-key]'))keyForm(key).catch(err=>toast(err.message,'error'));if(e.target.closest('[data-revoke-key]')&&confirm('Revocar esta API key la invalidará inmediatamente. ¿Continuar?'))api(`/api/admin/api-keys/${encodeURIComponent(key.key_id)}`,{method:'DELETE'}).then(()=>{toast('API key revocada');loadKeys()}).catch(err=>toast(err.message,'error'));if(e.target.closest('[data-reactivate-key]')&&confirm('La key volverá a aceptar su secreto original. ¿Reactivar?'))api(`/api/admin/api-keys/${encodeURIComponent(key.key_id)}/reactivate`,{method:'POST',body:'{}'}).then(()=>{toast('API key reactivada');loadKeys()}).catch(err=>toast(err.message,'error'));});$("#tool-filter").addEventListener('input',renderTools);$("#tool-class-filter").addEventListener('change',renderTools);$("#tools-list").addEventListener('change',(e)=>{if(!e.target.matches('[data-tool-toggle]'))return;const row=e.target.closest('[data-tool]');api(`/api/admin/tools/${encodeURIComponent(row.dataset.tool)}`,{method:'PATCH',body:JSON.stringify({enabled:e.target.checked})}).then(()=>{const tool=state.tools.find(t=>t.name===row.dataset.tool);tool.enabled=e.target.checked;renderTools();toast(`Tool ${e.target.checked?'habilitada':'deshabilitada'}`)}).catch(err=>{e.target.checked=!e.target.checked;toast(err.message,'error')});});
$("#refresh-actions").addEventListener('click',()=>loadOperation().catch(err=>toast(err.message,'error')));$("#refresh-logs").addEventListener('click',()=>loadOperation().catch(err=>toast(err.message,'error')));$("#copy-diagnostics").addEventListener('click',()=>navigator.clipboard.writeText($("#diagnostics-preview").textContent).then(()=>toast('Diagnóstico copiado')));$("#save-ports").addEventListener('click',()=>api('/api/admin/system/ports',{method:'PATCH',body:JSON.stringify({api_port:Number($("#system-api-port").value),portal_port:Number($("#system-portal-port").value),allow_beta_updates:$("#system-allow-beta").checked})}).then(()=>toast('Configuración guardada')).catch(err=>toast(err.message,'error')));$("#check-update").addEventListener('click',()=>api('/api/admin/system/check-update',{method:'POST',body:'{}'}).then(r=>{$("#update-state").textContent=r.update_available?'Actualización disponible':'Al día';toast($("#update-state").textContent)}).catch(err=>toast(err.message,'error')));$("#request-update").addEventListener('click',()=>{if(confirm('¿Solicitar la actualización del bridge?'))api('/api/admin/system/update',{method:'POST',body:JSON.stringify({allow_beta:$("#system-allow-beta").checked})}).then(()=>toast('Actualización solicitada')).catch(err=>toast(err.message,'error'))});$("#restart-service").addEventListener('click',()=>{if(confirm('El portal estará unos segundos sin conexión. ¿Reiniciar?'))api('/api/admin/system/restart',{method:'POST',body:'{}'}).then(()=>toast('Reinicio solicitado')).catch(err=>toast(err.message,'error'))});

$("#modal-content").addEventListener('click',(e)=>{const transfer=e.target.closest('[data-transfer-target]');if(!transfer)return;api('/api/roon/zones/transfer',{method:'POST',body:JSON.stringify({source_zone_id:transfer.dataset.transferSource,target_zone_id:transfer.dataset.transferTarget})}).then(()=>{closeModal();toast('Reproducción transferida');loadZones()}).catch(err=>toast(err.message,'error'));});

// Modal actions and forms
document.addEventListener('click',(e)=>{if(e.target.closest('[data-close]'))closeModal();const play=e.target.closest('#modal [data-play-media]');if(play)chooseZoneAndPlay(play.dataset.playMedia).catch(err=>toast(err.message,'error'));const radio=e.target.closest('#modal [data-radio-media]');if(radio)chooseZoneAndPlay(radio.dataset.radioMedia,'replace_queue',true).catch(err=>toast(err.message,'error'));const add=e.target.closest('#modal [data-add-playlist]');if(add)choosePlaylist(add.dataset.addPlaylist).catch(err=>toast(err.message,'error'));const zone=e.target.closest('[data-zone-play]');if(zone)playMedia(zone.dataset.result,zone.dataset.zone,zone.dataset.mode,zone.dataset.radio==='true').catch(err=>toast(err.message,'error'));const target=e.target.closest('[data-target-playlist]');if(target)api(`/api/playlists/${encodeURIComponent(target.dataset.targetPlaylist)}/tracks/from-search-result`,{method:'POST',body:JSON.stringify({result_id:target.dataset.result})}).then(()=>{toast('Añadido a la playlist');closeModal();loadPlaylists()}).catch(err=>toast(err.message,'error'));const create=e.target.closest('[data-create-with-result]');if(create){const result=create.dataset.createWithResult;playlistForm();$("#playlist-form").dataset.result=result;}const media=e.target.closest('#modal [data-media-id]');if(media&&!e.target.closest('[data-play-media]'))openMedia(media.dataset.mediaId).catch(err=>toast(err.message,'error'));});
$("#modal-content").addEventListener('click',(e)=>{if(!state.selectedPlaylist)return;if(e.target.closest('[data-edit-playlist]'))playlistForm(state.selectedPlaylist);if(e.target.closest('[data-delete-playlist]')&&confirm('Esta acción eliminará la playlist. ¿Continuar?'))api(`/api/playlists/${encodeURIComponent(state.selectedPlaylist.playlist_id)}?confirm=true`,{method:'DELETE',body:JSON.stringify({confirm:true})}).then(()=>{closeModal();toast('Playlist eliminada');loadPlaylists()}).catch(err=>toast(err.message,'error'));if(e.target.closest('[data-add-track]')){const id=state.selectedPlaylist.playlist_id;openModal(`${modalHead('Añadir canción','Buscar y resolver una pista')}<form id="add-track-form" class="modal-grid"><input type="hidden" name="playlist_id" value="${esc(id)}"><label class="full">Canción, artista o álbum<input name="query" required placeholder="Everything In Its Right Place Radiohead"></label><div class="modal-actions full"><button type="button" class="btn secondary" data-close>Cancelar</button><button class="btn primary" type="submit">Buscar y añadir</button></div></form>`)}const row=e.target.closest('[data-track]');if(row&&e.target.closest('[data-remove-track]')&&confirm('¿Quitar esta canción?'))api(`/api/playlists/${encodeURIComponent(state.selectedPlaylist.playlist_id)}/tracks/${encodeURIComponent(row.dataset.track)}?confirm=true`,{method:'DELETE',body:JSON.stringify({confirm:true})}).then(()=>openPlaylist(state.selectedPlaylist.playlist_id)).catch(err=>toast(err.message,'error'));if(row&&e.target.closest('[data-use-cover]')){const track=state.selectedPlaylist.tracks.find(t=>t.track_id===row.dataset.track);if(!track.image_key)return toast('Esta canción no tiene carátula','error');api(`/api/playlists/${encodeURIComponent(state.selectedPlaylist.playlist_id)}`,{method:'PATCH',body:JSON.stringify({cover_image_key:track.image_key})}).then(()=>{toast('Carátula actualizada');openPlaylist(state.selectedPlaylist.playlist_id)}).catch(err=>toast(err.message,'error'));}const play=e.target.closest('[data-play-playlist]');if(play){const zone=activeZone();if(!zone)return toast('No hay zona disponible','error');api(`/api/playlists/${encodeURIComponent(state.selectedPlaylist.playlist_id)}/play`,{method:'POST',body:JSON.stringify({zone_id:zone.zone_id,mode:play.dataset.playPlaylist})}).then(()=>toast('Playlist enviada a Roon')).catch(err=>toast(err.message,'error'));}});
document.addEventListener('change',(e)=>{if(e.target.matches('#key-form [name=all_tools]'))togglePermissionList();});
document.addEventListener('submit',async(e)=>{const form=e.target;if(!form.closest('dialog'))return;if(form.id==='playlist-form'){e.preventDefault();const data=formDataObject(form);const resultId=form.dataset.result;try{const playlist=await api(data.playlist_id?`/api/playlists/${encodeURIComponent(data.playlist_id)}`:'/api/playlists',{method:data.playlist_id?'PATCH':'POST',body:JSON.stringify({name:data.name,description:data.description})});if(resultId)await api(`/api/playlists/${encodeURIComponent(playlist.playlist_id)}/tracks/from-search-result`,{method:'POST',body:JSON.stringify({result_id:resultId})});closeModal();toast(data.playlist_id?'Playlist actualizada':'Playlist creada');await loadPlaylists();}catch(err){toast(err.message,'error')}}if(form.id==='add-track-form'){e.preventDefault();const data=formDataObject(form);try{await api(`/api/playlists/${encodeURIComponent(data.playlist_id)}/tracks`,{method:'POST',body:JSON.stringify({query:data.query})});toast('Canción añadida');await openPlaylist(data.playlist_id)}catch(err){toast(err.message,'error')}}if(form.id==='group-form'){e.preventDefault();const data=formDataObject(form);const members=[].concat(data.members||[]).filter(id=>id!==data.primary);try{await api('/api/roon/zones/group',{method:'POST',body:JSON.stringify({primary_zone_id:data.primary,zone_ids:[data.primary,...members]})});closeModal();toast('Zonas agrupadas');await loadZones()}catch(err){toast(err.message,'error')}}if(form.id==='preset-form'){e.preventDefault();const data=formDataObject(form);const [pt,...pv]=data.primary.split(':');const members=[].concat(data.members||[]).map(v=>{const [type,...value]=v.split(':');return{type,value:value.join(':')}});try{await api('/api/zone-presets',{method:'POST',body:JSON.stringify({name:data.name,description:data.description,grouping:{enabled:true,primary_zone_ref:{type:pt,value:pv.join(':')},members},volumes:[],playback:{action:'keep_current'},queue:{action:'keep_current'},virtual_zone:{enabled:true,display_name:data.name,show_in_portal:true,show_in_roon_if_supported:false}})});closeModal();toast('Preset creado');await loadPresets()}catch(err){toast(err.message,'error')}}if(form.id==='limit-form'){e.preventDefault();const data=formDataObject(form);const [type,...value]=data.target.split(':');try{await api(data.limit_id?`/api/volume-limits/${encodeURIComponent(data.limit_id)}`:'/api/volume-limits',{method:data.limit_id?'PUT':'POST',body:JSON.stringify({name:data.name,target_ref:{type,value:value.join(':')},safe_max:Number(data.safe_max),schedule:null,enabled:true})});closeModal();toast('Límite guardado');await loadPresets()}catch(err){toast(err.message,'error')}}if(form.id==='key-form'){e.preventDefault();const data=formDataObject(form);const all=form.elements.all_tools.checked;const permissions=all?null:[].concat(data.tools||[]);try{const result=await api(data.key_id?`/api/admin/api-keys/${encodeURIComponent(data.key_id)}`:'/api/admin/api-keys',{method:data.key_id?'PATCH':'POST',body:JSON.stringify({name:data.name,role:data.role,tool_permissions:permissions})});closeModal();if(result.token){$("#new-secret").textContent=result.token;$("#secret-dialog").showModal()}toast(data.key_id?'Permisos actualizados':'API key creada');await loadKeys()}catch(err){toast(err.message,'error')}}});
$("#copy-secret").addEventListener('click',()=>navigator.clipboard.writeText($("#new-secret").textContent).then(()=>toast('API key copiada')));$("#secret-dialog").addEventListener('click',(e)=>{if(e.target.closest('[data-close]'))$("#secret-dialog").close()});$("#mini-player").addEventListener('click',(e)=>{const b=e.target.closest('[data-mini-command]');if(b){const z=activeZone();if(z)zoneCommand(z.zone_id,b.dataset.miniCommand).catch(err=>toast(err.message,'error'))}});

bootstrapAuth().catch((error) => showAuth(error.message));
